prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?choreoName ?parallelGateway ?pgName WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "1ad939eef40c461dafae27f75a0586d3" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .
  ?parallelGateway a bboExt:ParallelGateway ;
                   tai:belongsTo ?choreo .
  OPTIONAL { ?parallelGateway bbo:name ?pgName . }
  OPTIONAL {
    ?choreo bbo:name ?choreoName .
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?idField ?idValue ?choreo ?choreoName
       (COUNT(DISTINCT ?pg) AS ?parallelGatewayCount)
       (COUNT(DISTINCT ?xor) AS ?exclusiveGatewayCount)
       (COUNT(DISTINCT ?ev) AS ?eventGatewayCount)
WHERE {
  VALUES ?idValue { "1ad939eef40c461dafae27f75a0586d3" }

  ?model a bboExt:Model .
  OPTIONAL { ?model tai:normalizedId ?idValue . BIND("normalizedId" AS ?idField) }
  OPTIONAL { ?model tai:originalId ?idValue . BIND("originalId" AS ?idField) }
  OPTIONAL { ?model bbo:name ?modelName . }

  FILTER(BOUND(?idField))

  ?model tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  OPTIONAL { ?choreo a bboExt:Choreography ; tai:belongsTo ?defs . }
  OPTIONAL { ?choreo bbo:name ?choreoName . }

  OPTIONAL { ?pg a bboExt:ParallelGateway ; tai:belongsTo ?choreo . }
  OPTIONAL { ?xor a bboExt:ExclusiveGateway ; tai:belongsTo ?choreo . }
  OPTIONAL { ?ev a bboExt:EventBasedGateway ; tai:belongsTo ?choreo . }
}
GROUP BY ?model ?modelName ?idField ?idValue ?choreo ?choreoName
ORDER BY DESC(?parallelGatewayCount)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?gw ?gwType ?gwName
       (COUNT(DISTINCT ?outEdge) AS ?outDegree)
       (GROUP_CONCAT(DISTINCT COALESCE(?nextName, STR(?next)); separator=" | ") AS ?nexts)
WHERE {
  VALUES ?idValue { "1ad939eef40c461dafae27f75a0586d3" }

  ?model a bboExt:Model ;
         tai:originalId ?idValue ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .

  ?gw a ?gwType ; tai:belongsTo ?choreo .
  FILTER(?gwType IN (bboExt:ExclusiveGateway, bboExt:EventBasedGateway, bboExt:ParallelGateway))

  OPTIONAL { ?gw bbo:name ?gwName . }

  ?outEdge a bbo:SequenceFlow ;
           bbo:has_sourceRef ?gw ;
           bbo:has_targetRef ?next .
  OPTIONAL { ?next bbo:name ?nextName . }
}
GROUP BY ?gw ?gwType ?gwName
ORDER BY DESC(?outDegree)
LIMIT 25
